// src/components/TelaAgendamentos.js
import React, { useState, useEffect } from "react";
import axios from "axios";
import Modal from "./Modal";
import FormAgendamento from "./FormAgendamento";

export default function TelaAgendamentos() {
  const [agendamentos, setAgendamentos] = useState([]);
  const [carregando, setCarregando] = useState(true);
  const [mostrarModal, setMostrarModal] = useState(false);
  const [agendamentoEditando, setAgendamentoEditando] = useState(null);

  // Filtros/Busca (se você já tinha, mantenha aqui)
  const [busca, setBusca] = useState("");
  const [filtroData, setFiltroData] = useState("");
  const [filtroHora, setFiltroHora] = useState("");

  useEffect(() => {
    carregarAgendamentos();
  }, []);

  function carregarAgendamentos() {
    setCarregando(true);
    axios
      .get("/api/agendamentos")
      .then((res) => {
        setAgendamentos(res.data);
        setCarregando(false);
      })
      .catch(() => setCarregando(false));
  }

  function onEditar(ag) {
    setAgendamentoEditando(ag);
    setMostrarModal(true);
  }

  function onNovo() {
    carregarAgendamentos();
  }

  function onFecharModal() {
    setAgendamentoEditando(null);
    setMostrarModal(false);
  }

  if (carregando) {
    return <p>Carregando agendamentos...</p>;
  }

  return (
    <div className="mt-4">
      <h2 className="text-xl font-semibold mb-4 text-[#1d3557]">
        Lista de Agendamentos
      </h2>

      {/* Botão “Agendar Paciente” sempre visível */}
      <button
        className="mb-4 bg-green-500 text-white px-4 py-2 rounded-full"
        onClick={() => setMostrarModal(true)}
      >
        Agendar Paciente
      </button>

      {/* Se não houver nenhum agendamento, exibe mensagem */}
      {agendamentos.length === 0 && (
        <p className="text-gray-500">Nenhum agendamento cadastrado.</p>
      )}

      {/* Se existirem agendamentos, exibe filtros e lista */}
      {agendamentos.length > 0 && (
        <>
          {/* Exemplo de filtros (opcional) */}
          <div className="flex flex-col md:flex-row md:items-end gap-3 p-4 pt-0 pb-4 rounded-2xl bg-white mb-6">
            <div className="flex-1">
              <label className="block text-sm font-medium mb-2">
                Pesquisar
              </label>
              <input
                type="text"
                className="border rounded px-4 py-2 w-full rounded-2xl"
                placeholder="Operador, Auxiliar, Período, Paciente ou Status"
                value={busca}
                onChange={(e) => setBusca(e.target.value)}
              />
            </div>
            {/* Se tiver ícones de filtro por data/hora, coloque aqui */}
          </div>

          {/* Cabeçalho (desktop) */}
          <div className="hidden md:grid md:grid-cols-7 gap-x-4 px-5 py-2 bg-gray-100 rounded-t-xl font-semibold text-gray-600 mb-2">
            <span className="truncate">Operador</span>
            <span className="truncate">Auxiliar</span>
            <span className="truncate">Paciente</span>
            <span className="truncate">Telefone</span>
            <span className="truncate">Data</span>
            <span className="truncate">Hora</span>
            <span className="truncate text-right">Ações</span>
          </div>

          {/* Lista de agendamentos */}
          <ul className="space-y-3">
            {agendamentos
              .filter((ag) => {
                // sua lógica de filtragem, se houver
                return true;
              })
              .map((ag) => (
                <li
                  key={ag.id}
                  className="flex flex-col md:grid md:grid-cols-7 gap-y-1 gap-x-4 items-center bg-gray-50 rounded-xl px-4 md:px-5 py-2 shadow-sm hover:bg-gray-100 transition"
                >
                  <div className="w-full font-medium text-gray-800 truncate">
                    {ag.operadorNome || "-"}
                  </div>
                  <div className="w-full text-gray-800 truncate">
                    {ag.auxiliarNome || "-"}
                  </div>
                  <div className="w-full text-gray-800 truncate">
                    {ag.pacienteNome || "-"}
                  </div>
                  <div className="w-full text-gray-500 truncate">
                    {ag.telefone || "-"}
                  </div>
                  <div className="w-full text-gray-800 truncate">
                    {ag.data
                      ? ag.data.slice(0, 10).split("-").reverse().join("/")
                      : "-"}
                  </div>
                  <div className="w-full text-gray-800 truncate">
                    {ag.hora || "-"}
                  </div>
                  <div className="flex flex-row items-center gap-2 w-full md:justify-end">
                    <button
                      onClick={() => onEditar(ag)}
                      className="px-3 py-1 rounded-lg bg-blue-100 text-blue-800 hover:bg-blue-200 font-semibold transition"
                    >
                      Editar
                    </button>
                    <button
                      onClick={() => {
                        if (
                          window.confirm(
                            "Tem certeza que deseja deletar este agendamento?"
                          )
                        ) {
                          axios
                            .delete(`/api/agendamentos/${ag.id}`)
                            .then(() => carregarAgendamentos());
                        }
                      }}
                      className="px-3 py-1 rounded-lg bg-red-100 text-red-700 hover:bg-red-200 font-semibold transition"
                    >
                      Deletar
                    </button>
                  </div>
                </li>
              ))}
          </ul>
        </>
      )}

      {/* Modal para criar/editar agendamento */}
      {mostrarModal && (
        <Modal isOpen={mostrarModal} onRequestClose={onFecharModal}>
          <FormAgendamento
            agendamentoEditando={agendamentoEditando}
            onNovoAgendamento={onNovo}
            onFimEdicao={onFecharModal}
          />
        </Modal>
      )}
    </div>
  );
}
